// 🔹 GET todos os lutadores
app.get("/lutadores", (req, res) => {
    res.json(lutadores);
});

// 🔹 GET por id ou nome
app.get("/lutadores/:idOuNome", (req, res) => {
    const valor = req.params.idOuNome.toLowerCase();

    const lutador = lutadores.find(l =>
        l.id == valor || l.nome.toLowerCase() === valor
    );

    if (!lutador) {
        return res.status(404).json({ mensagem: "Lutador não encontrado!" });
    }

    res.json(lutador);
});

// 🔹 GET por nacionalidade
app.get("/lutadores/nacionalidade/:nacionalidade", (req, res) => {
    const nat = req.params.nacionalidade.toLowerCase();

    const resultado = lutadores.filter(l =>
        l.nacionalidade.toLowerCase() === nat
    );

    res.json(resultado);
});

// 🔹 GET por estilo
app.get("/lutadores/estilo/:estilo", (req, res) => {
    const estilo = req.params.estilo.toLowerCase();

    const resultado = lutadores.filter(l =>
        l.estilo.toLowerCase() === estilo
    );

    res.json(resultado);
});

// 🔹 GET por categoria
app.get("/lutadores/categoria/:categoria", (req, res) => {
    const cat = req.params.categoria.toLowerCase();

    const resultado = lutadores.filter(l =>
        l.categoria.toLowerCase() === cat
    );

    res.json(resultado);
});

app.listen(process.env.PORTA, () => {
    console.log(`Servidor rodando: http://127.0.0.1:${process.env.PORTA}`);
});